import{c as s,Q as a,j as i,m as t}from"./chunks/framework.Byb9vlc_.js";const k=JSON.parse('{"title":"SeaweedFS (S3-compatible Object Store)","description":"","frontmatter":{},"headers":[],"relativePath":"showcases/seaweedfs.md","filePath":"showcases/seaweedfs.md","lastUpdated":1780497592000}'),l={name:"showcases/seaweedfs.md"};function n(h,e,d,o,p,r){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="seaweedfs-s3-compatible-object-store" tabindex="-1">SeaweedFS (S3-compatible Object Store) <a class="header-anchor" href="#seaweedfs-s3-compatible-object-store" aria-label="Permalink to &quot;SeaweedFS (S3-compatible Object Store)&quot;">​</a></h1><h3 id="description" tabindex="-1">Description <a class="header-anchor" href="#description" aria-label="Permalink to &quot;Description&quot;">​</a></h3><p><a href="https://seaweedfs.com/" target="_blank" rel="noreferrer">SeaweedFS</a> is a fast, distributed object store with an Apache-2.0 license. This showcase deploys a single-pod, all-in-one SeaweedFS instance that exposes an S3-compatible endpoint inside the cluster. It serves as a lightweight, license-friendly alternative to MinIO for demos that need an object store — for example as the backup target for the <a href="./velero.html">Velero</a> showcase.</p><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/seaweedfs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span></span></code></pre></div><p>Optionally pass an additional bucket name to create:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-extra-bucket</span></span></code></pre></div><p>The setup script:</p><ul><li>Creates the <code>seaweedfs</code> namespace</li><li>Deploys SeaweedFS as a <code>StatefulSet</code> running <code>weed server -filer -s3</code> (master, volume, filer and S3 gateway in one pod)</li><li>Provisions a 10 GiB PVC for object data</li><li>Creates a default bucket called <code>demo</code></li></ul><h3 id="endpoint-and-credentials" tabindex="-1">Endpoint and credentials <a class="header-anchor" href="#endpoint-and-credentials" aria-label="Permalink to &quot;Endpoint and credentials&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>In-cluster S3 endpoint</td><td><code>http://seaweedfs-s3.seaweedfs.svc.cluster.local:8333</code></td></tr><tr><td>Filer HTTP API</td><td><code>http://seaweedfs.seaweedfs.svc.cluster.local:8888</code></td></tr><tr><td>Master HTTP API</td><td><code>http://seaweedfs.seaweedfs.svc.cluster.local:9333</code></td></tr><tr><td>Access key</td><td><code>seaweedadmin</code></td></tr><tr><td>Secret key</td><td><code>seaweedadminsecret</code></td></tr></tbody></table><blockquote><p>The credentials are static and committed to this repo. They are intended for <strong>local Lab use only</strong> — never reuse them in any environment that is reachable beyond your machine.</p></blockquote><h3 id="smoke-test-with-the-aws-cli" tabindex="-1">Smoke test with the AWS CLI <a class="header-anchor" href="#smoke-test-with-the-aws-cli" aria-label="Permalink to &quot;Smoke test with the AWS CLI&quot;">​</a></h3><p>From inside the cluster (or via <code>kubectl run</code> with the <code>amazon/aws-cli</code> image):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aws-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --restart=Never</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --image=amazon/aws-cli:latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --env=AWS_ACCESS_KEY_ID=seaweedadmin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --env=AWS_SECRET_ACCESS_KEY=seaweedadminsecret</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --endpoint-url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://seaweedfs-s3.seaweedfs:8333</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><h3 id="managing-buckets-via-weed-shell" tabindex="-1">Managing buckets via <code>weed shell</code> <a class="header-anchor" href="#managing-buckets-via-weed-shell" aria-label="Permalink to &quot;Managing buckets via \`weed shell\`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seaweedfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seaweedfs-0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;echo &#39;s3.bucket.list&#39; | weed shell -master localhost:9333 -filer localhost:8888&quot;</span></span></code></pre></div><h3 id="used-by" tabindex="-1">Used by <a class="header-anchor" href="#used-by" aria-label="Permalink to &quot;Used by&quot;">​</a></h3><ul><li><a href="./velero.html">Velero Backup &amp; Restore</a> — uses SeaweedFS as the backup storage location.</li></ul><h3 id="cleanup" tabindex="-1">Cleanup <a class="header-anchor" href="#cleanup" aria-label="Permalink to &quot;Cleanup&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seaweedfs</span></span></code></pre></div>`,21)])])}const F=s(l,[["render",n]]);export{k as __pageData,F as default};
